1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	}
14	
15	interface QuoteStep {
16	  items: Item[];
17	}
18	
19	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
20	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
21	// that is only spuriously above a whole number.
22	const roundUpInMHPCOsFavor = (amount: number): number =>
23	  Math.ceil(Number(amount.toFixed(6)));
24	
25	export const quote = (
26	  customer: unknown,
27	  step: QuoteStep,
28	  quoteIndex: number,
29	): number => {
30	  const basePremium = step.items.reduce(
31	    (sum, item) => sum + (BASE_PREMIUM_BY_TYPE[item.type] ?? 0),
32	    0,
33	  );
34	  const withFirstInsurance = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
35	  const total = withFirstInsurance + PROCESSING_FEE;
36	  return roundUpInMHPCOsFavor(total);
37	};
38	
